import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  Typography,
  TextField,
  Button,
  Grid,
  Switch,
  FormControlLabel,
  Divider,
  Slider,
  Alert
} from '@mui/material';
import { Save as SaveIcon } from '@mui/icons-material';

interface OrganizationSettings {
  name: string;
  logo: string;
  primaryColor: string;
  secondaryColor: string;
}

interface AISettings {
  scoringWeights: {
    technical: number;
    communication: number;
    problemSolving: number;
    teamFit: number;
  };
  interviewTone: 'professional' | 'casual' | 'technical';
  questionTemplates: string[];
  autoEvaluation: boolean;
  feedbackLanguage: string;
}

const AdminSettings: React.FC = () => {
  const [organizationSettings, setOrganizationSettings] = useState<OrganizationSettings>({
    name: '',
    logo: '',
    primaryColor: '#1976d2',
    secondaryColor: '#dc004e'
  });

  const [aiSettings, setAISettings] = useState<AISettings>({
    scoringWeights: {
      technical: 40,
      communication: 20,
      problemSolving: 20,
      teamFit: 20
    },
    interviewTone: 'professional',
    questionTemplates: [],
    autoEvaluation: true,
    feedbackLanguage: 'en'
  });

  const [saved, setSaved] = useState(false);

  useEffect(() => {
    fetchSettings();
  }, []);

  const fetchSettings = async () => {
    try {
      const [orgResponse, aiResponse] = await Promise.all([
        fetch('/api/admin/settings/organization'),
        fetch('/api/admin/settings/ai')
      ]);

      if (orgResponse.ok && aiResponse.ok) {
        const [orgData, aiData] = await Promise.all([
          orgResponse.json(),
          aiResponse.json()
        ]);
        setOrganizationSettings(orgData);
        setAISettings(aiData);
      }
    } catch (error) {
      console.error('Error fetching settings:', error);
    }
  };

  const handleSave = async () => {
    try {
      const [orgResponse, aiResponse] = await Promise.all([
        fetch('/api/admin/settings/organization', {
          method: 'PUT',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify(organizationSettings),
        }),
        fetch('/api/admin/settings/ai', {
          method: 'PUT',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify(aiSettings),
        }),
      ]);

      if (orgResponse.ok && aiResponse.ok) {
        setSaved(true);
        setTimeout(() => setSaved(false), 3000);
      }
    } catch (error) {
      console.error('Error saving settings:', error);
    }
  };

  const handleWeightChange = (key: keyof AISettings['scoringWeights']) => (
    event: Event,
    newValue: number | number[]
  ) => {
    setAISettings(prev => ({
      ...prev,
      scoringWeights: {
        ...prev.scoringWeights,
        [key]: newValue as number
      }
    }));
  };

  return (
    <Box sx={{ p: 3 }}>
      <Typography variant="h4" gutterBottom>
        Admin Settings
      </Typography>

      {saved && (
        <Alert severity="success" sx={{ mb: 3 }}>
          Settings saved successfully!
        </Alert>
      )}

      <Grid container spacing={3}>
        {/* Organization Settings */}
        <Grid item xs={12} md={6}>
          <Paper sx={{ p: 3 }}>
            <Typography variant="h6" gutterBottom>
              Organization Settings
            </Typography>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <TextField
                  label="Organization Name"
                  value={organizationSettings.name}
                  onChange={(e) => setOrganizationSettings(prev => ({
                    ...prev,
                    name: e.target.value
                  }))}
                  fullWidth
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  label="Logo URL"
                  value={organizationSettings.logo}
                  onChange={(e) => setOrganizationSettings(prev => ({
                    ...prev,
                    logo: e.target.value
                  }))}
                  fullWidth
                />
              </Grid>
              <Grid item xs={12} sm={6}>
                <TextField
                  label="Primary Color"
                  type="color"
                  value={organizationSettings.primaryColor}
                  onChange={(e) => setOrganizationSettings(prev => ({
                    ...prev,
                    primaryColor: e.target.value
                  }))}
                  fullWidth
                />
              </Grid>
              <Grid item xs={12} sm={6}>
                <TextField
                  label="Secondary Color"
                  type="color"
                  value={organizationSettings.secondaryColor}
                  onChange={(e) => setOrganizationSettings(prev => ({
                    ...prev,
                    secondaryColor: e.target.value
                  }))}
                  fullWidth
                />
              </Grid>
            </Grid>
          </Paper>
        </Grid>

        {/* AI Interview Settings */}
        <Grid item xs={12} md={6}>
          <Paper sx={{ p: 3 }}>
            <Typography variant="h6" gutterBottom>
              AI Interview Settings
            </Typography>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <Typography gutterBottom>
                  Scoring Weights
                </Typography>
                <Box sx={{ px: 2 }}>
                  <Typography gutterBottom>
                    Technical Skills
                  </Typography>
                  <Slider
                    value={aiSettings.scoringWeights.technical}
                    onChange={handleWeightChange('technical')}
                    valueLabelDisplay="auto"
                  />
                  <Typography gutterBottom>
                    Communication
                  </Typography>
                  <Slider
                    value={aiSettings.scoringWeights.communication}
                    onChange={handleWeightChange('communication')}
                    valueLabelDisplay="auto"
                  />
                  <Typography gutterBottom>
                    Problem Solving
                  </Typography>
                  <Slider
                    value={aiSettings.scoringWeights.problemSolving}
                    onChange={handleWeightChange('problemSolving')}
                    valueLabelDisplay="auto"
                  />
                  <Typography gutterBottom>
                    Team Fit
                  </Typography>
                  <Slider
                    value={aiSettings.scoringWeights.teamFit}
                    onChange={handleWeightChange('teamFit')}
                    valueLabelDisplay="auto"
                  />
                </Box>
              </Grid>
              <Grid item xs={12}>
                <FormControlLabel
                  control={
                    <Switch
                      checked={aiSettings.autoEvaluation}
                      onChange={(e) => setAISettings(prev => ({
                        ...prev,
                        autoEvaluation: e.target.checked
                      }))}
                    />
                  }
                  label="Enable Auto-Evaluation"
                />
              </Grid>
            </Grid>
          </Paper>
        </Grid>
      </Grid>

      <Box sx={{ mt: 3, display: 'flex', justifyContent: 'flex-end' }}>
        <Button
          variant="contained"
          startIcon={<SaveIcon />}
          onClick={handleSave}
        >
          Save Settings
        </Button>
      </Box>
    </Box>
  );
};

export default AdminSettings;
